import { getOrderlyEnvConfig } from "@/utils/environment";
import { apiClient } from "@/utils/api";
import { walletSetItem, setLastWalletAddress } from "@/utils/storage";

export type WalletAuthResult = {
  message: string;
  signature: string;
  token?: string;
};

const WALLET_AUTH_REUSE_MS = 15_000;

let activeWalletAuth: {
  key: string;
  promise: Promise<WalletAuthResult>;
} | null = null;

let recentWalletAuth: {
  key: string;
  result: WalletAuthResult;
  expiresAt: number;
} | null = null;

export function resetWalletAuthCache(): void {
  activeWalletAuth = null;
  recentWalletAuth = null;
}

export function getAuthApiBaseUrl(): string | null {
  return getOrderlyEnvConfig().dexApiBaseUrl;
}

export function buildLocalOwnershipMessage(walletAddress: string): string {
  return [
    "Orderly One wants you to verify wallet ownership.",
    "",
    `Wallet: ${walletAddress}`,
    `Nonce: ${crypto.randomUUID()}`,
    `Issued At: ${new Date().toISOString()}`,
  ].join("\n");
}

export async function verifyWalletOwnership(
  walletAddressForVerification: string,
  signMessageAsync: (args: { message: string }) => Promise<string>
): Promise<WalletAuthResult> {
  setLastWalletAddress(walletAddressForVerification);
  const key = `${getOrderlyEnvConfig().env}:${walletAddressForVerification.toLowerCase()}`;

  if (
    recentWalletAuth?.key === key &&
    recentWalletAuth.expiresAt > Date.now()
  ) {
    return recentWalletAuth.result;
  }

  if (activeWalletAuth?.key === key) {
    return activeWalletAuth.promise;
  }

  const promise = Promise.resolve().then(
    async (): Promise<WalletAuthResult> => {
      const authApiBaseUrl = getAuthApiBaseUrl();

      if (authApiBaseUrl) {
        let nonceData: { message?: string };
        try {
          nonceData = await apiClient<{ message?: string }>({
            endpoint: "/api/auth/nonce",
            method: "POST",
            baseUrl: authApiBaseUrl,
            token: null,
            body: { address: walletAddressForVerification },
            showToastOnError: false,
          });
        } catch {
          throw new Error("Failed to get authentication nonce");
        }
        if (!nonceData.message)
          throw new Error("Authentication nonce response is missing a message");

        const signature = await signMessageAsync({
          message: nonceData.message,
        });

        let verifyData: { token?: string; user?: unknown };
        try {
          verifyData = await apiClient<{ token?: string; user?: unknown }>({
            endpoint: "/api/auth/verify",
            method: "POST",
            baseUrl: authApiBaseUrl,
            token: null,
            body: {
              address: walletAddressForVerification,
              signature,
            },
            showToastOnError: false,
          });
        } catch {
          throw new Error("Signature verification failed");
        }
        if (!verifyData.token)
          throw new Error(
            "Signature verification did not return an auth token"
          );

        let validateData: { valid?: boolean };
        try {
          validateData = await apiClient<{ valid?: boolean }>({
            endpoint: "/api/auth/validate",
            method: "POST",
            baseUrl: authApiBaseUrl,
            token: null,
            body: {
              address: walletAddressForVerification,
              token: verifyData.token,
            },
            showToastOnError: false,
          });
        } catch {
          throw new Error("Authentication token validation failed");
        }
        if (validateData.valid !== true)
          throw new Error("Authentication token is invalid");

        walletSetItem("auth_token", verifyData.token);
        if (verifyData.user)
          walletSetItem("auth_user", JSON.stringify(verifyData.user));

        return {
          message: nonceData.message,
          signature,
          token: verifyData.token,
        };
      }

      const message = buildLocalOwnershipMessage(walletAddressForVerification);
      const signature = await signMessageAsync({ message });
      walletSetItem(
        "orderlyWalletSignature",
        JSON.stringify({
          walletAddress: walletAddressForVerification,
          message,
          signature,
        })
      );
      return { message, signature };
    }
  );

  activeWalletAuth = { key, promise };
  try {
    const result = await promise;
    recentWalletAuth = {
      key,
      result,
      expiresAt: Date.now() + WALLET_AUTH_REUSE_MS,
    };
    return result;
  } finally {
    if (activeWalletAuth?.promise === promise) {
      activeWalletAuth = null;
    }
  }
}
